"    function openVisualEditor(pageId) {
      const page = cmsState.pages.find(p => p.id === pageId);
      if (!page) return;
      // Open the unified Theme Customizer and navigate to the page
      const customizeBtn = document.getElementById('customizeBtn');
      if (customizeBtn) {
        customizeBtn.click();
        setTimeout(() => {
          if (typeof showTab === 'function') showTab('Pages');
          setTimeout(() => {
            if (typeof selectCustomizerPage === 'function') selectCustomizerPage(pageId);
          }, 300);
        }, 300);
      }
    }"

