"    function openVisualEditor(pageId) {
      const page = cmsState.pages.find(p => p.id === pageId);
      if (!page) return;
      const params = new URLSearchParams({
        pageId: page.id,
        title: page.title || '',
        slug: page.slug || '',
        status: page.status || 'draft',
        theme: state.theme.mode,
        accent: state.theme.accent,
        v: Date.now().toString()
      });
      window.location.href = `/page-builder/?${params.toString()}`;
    }"
